/**
 * Build script: generates the VM serialization bundle.
 *
 * Uses esbuild to bundle workflow-vm.ts + TextEncoder/TextDecoder polyfills
 * into a self-contained IIFE. The output is written as a TypeScript file
 * containing the bundle as a string constant, which can be imported by
 * the snapshot runtime.
 *
 * The polyfills are injected via esbuild's `inject` option to ensure they
 * run before any other code (including module-level TextEncoder/TextDecoder
 * instantiation).
 */

import { buildSync } from 'esbuild';
import { writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const srcDir = resolve(__dirname, '../src');

const result = buildSync({
  entryPoints: [resolve(srcDir, 'serialization/vm-bundle-entry.ts')],
  inject: [resolve(srcDir, 'polyfills/install-text-coding.ts')],
  bundle: true,
  format: 'iife',
  platform: 'neutral',
  target: 'es2020',
  write: false,
  minify: true,
});

const bundleCode = result.outputFiles[0].text;

const output = `/**
 * Auto-generated by scripts/build-vm-serde-bundle.js
 * Do not edit manually.
 *
 * This is the VM serialization bundle — a self-contained IIFE that sets up
 * serialize/deserialize + TextEncoder/TextDecoder polyfills inside the
 * QuickJS WASM VM. It includes devalue and all workflow-mode reducers.
 *
 * Size: ${(bundleCode.length / 1024).toFixed(1)} KB minified
 */
export const VM_SERDE_BUNDLE = ${JSON.stringify(bundleCode)};
`;

writeFileSync(resolve(srcDir, 'runtime/vm-serde-bundle.generated.ts'), output);

console.log(
  `Generated vm-serde-bundle.generated.ts (${(bundleCode.length / 1024).toFixed(1)} KB)`
);
